class Solution {
public:
    vector<int> splitIntoFibonacci(string num) {
        int n = num.size();
        for (int i = 1; i <= min(n / 2, 10); ++i) {
            for (int j = 1; j <= min((n - i) / 2, 10); ++j) {
                vector<int> seq;
                if (i > 1 && num[0] == '0') continue;
                if (j > 1 && num[i] == '0') continue;
                long long a = stoll(num.substr(0, i));
                long long b = stoll(num.substr(i, j));
                if (a > INT_MAX || b > INT_MAX) continue;
                seq.push_back((int)a);
                seq.push_back((int)b);
                int pos = i + j;
                bool ok = true;
                while (pos < n) {
                    long long c = (long long)seq[seq.size() - 2] + seq[seq.size() - 1];
                    if (c > INT_MAX) { ok = false; break; }
                    string s = to_string(c);
                    if (pos + s.size() > n || num.substr(pos, s.size()) != s) { ok = false; break; }
                    seq.push_back((int)c);
                    pos += s.size();
                }
                if (ok && seq.size() >= 3) return seq;
            }
        }
        return {};
    }
};
```
